module RefModule (
  input clk,
  input reset,
  input [7:0] a,
  input [7:0] b,
  input ctrl,
  output [15:0] out
);

reg [15:0] unused_temp;

always @ (posedge clk or posedge reset) begin
  if (reset) begin
    unused_temp <= 16'b0;
  end else begin
    if (ctrl) begin
      unused_temp <= {a, b};
    end else begin
      unused_temp <= {b, a};
    end
  end
end

assign out = unused_temp;

endmodule
